import { createSlice } from "@reduxjs/toolkit";
import { configureStore } from "@reduxjs/toolkit";
import { persistStore, persistReducer } from 'redux-persist';
import storage from 'redux-persist/lib/storage'; // defaults to localStorage for web
import { combineReducers } from "redux";

const initialState={
    user:[{id:1,name:'abir'}],
    logged:[],
    home_page_info:[],
    train:[],



};

const variable=
{   
    name:'variable',
    initialState,
    reducers:{
        addItem:(state,action)=>{
            const item={
                id:'2',
                name:action.payload
            }
            state.user.push(item)
        },
        loginUser: (state,action)=>{
            state.logged.push(action.payload)
        },
        logoutUser:(state,action)=>{
            
            state.logged=[]

        },
        addUser:(state,action)=>{
            state.user.push(action.payload)
        },
        addDetails:(state,action)=>{
            state.journey_inf.push(action.payload)
        },
        showDetails:(state,action)=>{
            return state.journey_inf

    }
}}



const variableSlice=createSlice(variable)

// Persist Config
const persistConfig = {
    key: 'root',
    storage, // default to localStorage
};

// Combine reducers (in case you have multiple reducers)
const rootReducer = combineReducers({
    var: variableSlice.reducer,
});

// Create a persisted reducer
const persistedReducer = persistReducer(persistConfig, rootReducer);

// Create the store with persisted reducer
export const store = configureStore({
    reducer: persistedReducer,
});

// Create the persistor
export const persistor = persistStore(store);


export const {addItem,addDetails,showDetails,loginUser,addUser,logoutUser}=variableSlice.actions


